// Map Clio payload → normalized body (adjust keys to your Clio JSON)
const b = $json.body || $json;
const event = b.event_type || b.type || 'agreement_sent';
return [{
  json: {
    event,
    ghlContactId: b.ghl_contact_id || b.custom_fields?.ghl_contact_id,
    clioMatterId: b.matter_id || b.id,
    agreementStatus: b.agreement_status,
    paymentStatus: b.payment_status,
    caseValue: b.case_value || b.amount,
    matterNotes: b.notes || b.description || '',
    raw: b
  }
}];
